// KPI Card Component
const KpiCard = ({ title, value, benchmark, riskDirection, unit }) => {
  let deltaText = "vs Target: N/A";
  let deltaColorClass = "kpi-delta-good";

  if (value !== 'N/A' && benchmark !== 0) {
    try {
      const valueNum = parseFloat(value);
      const benchmarkNum = parseFloat(benchmark);
      const deltaValue = ((valueNum - benchmarkNum) / benchmarkNum) * 100;
      const isWorse = (deltaValue * riskDirection) > 0;
      deltaText = `vs Target: ${Math.abs(deltaValue).toFixed(1)}% ${isWorse ? 'Worse' : 'Better'}`;
      deltaColorClass = isWorse ? "kpi-delta-bad" : "kpi-delta-good";
    } catch (error) {
      deltaText = "vs Target: N/A";
    }
  }

  return (
    <div className="kpi-card">
      <div className="kpi-title">{title}</div>
      <div className="kpi-value">{value}{unit}</div>
      <div className={deltaColorClass}>{deltaText}</div>
    </div>
  );
};

// Risk Gauge Component
const RiskGauge = ({ probability }) => {
  const pct = probability * 100;
  let level, color;

  if (pct < 30) {
    level = 'LOW';
    color = 'green';
  } else if (pct < 70) {
    level = 'MODERATE';
    color = 'gold';
  } else {
    level = 'HIGH';
    color = 'red';
  }

  const data = {
    labels: ['Low', 'Moderate', 'High'],
    datasets: [
      {
        data: [30, 40, 30],
        backgroundColor: ['lightgreen', 'yellow', 'salmon'],
        borderWidth: 0,
        circumference: 180,
        rotation: 270,
      },
    ],
  };

  const options = {
    plugins: {
      legend: { display: false },
      tooltip: { enabled: false },
    },
    cutout: '60%',
  };

  const needle = {
    id: 'needle',
    afterDatasetsDraw(chart) {
      const { ctx } = chart;
      ctx.save();

      const angle = Math.PI + (1.5 * Math.PI * (pct / 100));
      const cx = chart.chartArea.left + (chart.chartArea.right - chart.chartArea.left) / 2;
      const cy = chart.chartArea.top + (chart.chartArea.bottom - chart.chartArea.top) / 2;
      const radius = (chart.chartArea.bottom - chart.chartArea.top) / 2;

      // Draw needle
      ctx.translate(cx, cy);
      ctx.rotate(angle);
      ctx.beginPath();
      ctx.moveTo(0, -5);
      ctx.lineTo(radius - 20, 0);
      ctx.lineTo(0, 5);
      ctx.closePath();
      ctx.fillStyle = '#1e293b';
      ctx.fill();

      // Draw needle center
      ctx.rotate(-angle);
      ctx.beginPath();
      ctx.arc(0, 0, 8, 0, 2 * Math.PI);
      ctx.fillStyle = '#1e293b';
      ctx.fill();

      ctx.restore();
    },
  };

  return (
    <div style={{ height: '280px', margin: '0 auto', maxWidth: '400px' }}>
      <Doughnut data={data} options={options} plugins={[needle]} />
    </div>
  );
};

